#include <stdio.h>
#include <string.h> // Required for String tools!

int main() {
    char name[] = "Hello";
    // %zu is for the 'size_t' type returned by strlen
    printf("Length is %zu\n", strlen(name)); // Prints 5
    return 0;
}

#include <stdio.h>
#include <string.h>

int main() {
    char source[] = "Copy Me!";
    char destination[20]; // We need a 20-slot empty box

    // Copy source into destination
    strcpy(destination, source);

    printf("Destination: %s\n", destination);
    return 0;
}
